function normalizePolishTypography(text) {
  return text
    .replaceAll("przekładu przekładu", "przekładu dokonanego z innego przekładu")
    .replaceAll("prawdziwie w prawdzie", "z całą pewnością")
    .replaceAll("pośpieszą szybko", "pośpieszą")
    .replaceAll("będzie nieistniejąca na wieczność", "przestanie istnieć na wieki")
    .replaceAll("dokonamy jakichś takich misteriów", "dokonamy jednego z takich misteriów")
    .replaceAll(
      "misteria aż do dwóch albo trzech |315. w drugiej albo trzeciej przestrzeni",
      "dwa lub trzy misteria |315. drugiej albo trzeciej przestrzeni"
    )
    .replaceAll("Maryja znowu kontynuowała i rzekła", "Maryja ponownie zabrała głos")
    .replaceAll("Maryja kontynuowała i rzekła", "Maryja mówiła dalej")
    .replaceAll("Jan znowu kontynuował i rzekł do Zbawcy", "Jan ponownie zwrócił się do Zbawcy")
    .replaceAll("Jan znowu kontynuował i rzekł", "Jan mówił dalej")
    .replaceAll("Zbawca znowu kontynuował i rzekł", "Zbawca mówił dalej")
    .replaceAll("Zbawca kontynuował i rzekł", "Zbawca mówił dalej")
    .replaceAll("Jezus kontynuował i rzekł", "Jezus mówił dalej")
    .replaceAll("Kontynuował i rzekł: 'Czwarty porządek", "Jezus mówił dalej: 'Czwarty porządek")
    .replaceAll("wystąpił naprzód", "wystąpił")
    .replaceAll("wystąpiła naprzód", "wystąpiła")
    .replaceAll("w jakim typie będą ci", "jaki będzie stan tych")
    .replaceAll("w jakim typie ustanowieni są", "w jaki sposób ustanowieni są")
    .replaceAll("w jakim typie więc |298. chrzty odpuszczają grzechy", "w jaki sposób więc |298. chrzty odpuszczają grzechy")
    .replaceAll("w jakim typie Misterium chrztu odpuszcza grzechy", "w jaki sposób Misterium chrztu odpuszcza grzechy")
    .replaceAll("w jakim typie odpuszczają grzechy", "w jaki sposób odpuszczają grzechy")
    .replaceAll("w jakim typie jest zewnętrzna ciemność", "jaka jest natura zewnętrznej ciemności")
    .replaceAll("W jakim typie jest zewnętrzna ciemność", "Jaka jest natura zewnętrznej ciemności")
    .replaceAll(
      "Powiem wam ich typ, w jakim typie wchodzą w ludzi",
      "Powiem wam, w jakiej postaci wchodzą w ludzi"
    )
    .replaceAll("przyszła czynić pokutę", "przyszła, aby pokutować")
    .replaceAll("nie zawrócił ku pokucie", "nie zwrócił się ku pokucie")
    .replaceAll("miłosiernie usposobione", "pełne miłosierdzia")
    .replaceAll(
      "otrzyma cierpienie w karaniach sądów, w wielkich cierpieniach i |316. sądach nadzwyczaj o wiele większych w porównaniu z bezbożnym i łamiącym prawo człowiekiem",
      "dozna w karach sądowych |316. cierpień o wiele większych niż bezbożny i łamiący prawo człowiek"
    )
    .replaceAll(
      "I stało się więc, gdy Jezus skończył mówić te słowa do swoich uczniów, że Maria Magdalena",
      "Gdy Jezus skończył mówić do swoich uczniów, Maria Magdalena"
    )
    .replaceAll(
      "I stało się więc, gdy Jezus skończył mówić te słowa do swoich uczniów, że Jan",
      "Gdy Jezus skończył mówić do swoich uczniów, Jan"
    )
    .replaceAll(
      "Teraz więc, Panie mój, miej dla mnie cierpliwość, gdy cię pytam.",
      "Panie mój, miej cierpliwość, gdy cię pytam."
    )
    .replaceAll(
      "Oto jawnie poznaliśmy typ, w którym chrzty odpuszczają grzechy.",
      "Poznaliśmy już sposób, w jaki chrzty odpuszczają grzechy."
    )
    .replaceAll(
      "człowiek, który poznał boskość i otrzymał misteria Światłości, i zgrzeszył, i nie zwrócił się ku pokucie",
      "człowiek, który poznał boskość i otrzymał misteria Światłości, lecz później zgrzeszył i nie zwrócił się ku pokucie"
    )
    .replaceAll("jako zgorszenie i jako przekraczający", "jako zgorszenie i jako ten, kto przekracza prawo")
    .replaceAll("jako przekraczający i jako zgorszenie", "jako ten, kto przekracza prawo, i jako zgorszenie")
    .replaceAll(
      "pójdzie i odziedziczy aż do krainy, aż do której otrzymał misteria",
      "dotrze do krainy odpowiadającej otrzymanym misteriom i ją odziedziczy"
    )
    .replaceAll(
      "każdy pójdzie do krainy, aż do której otrzymał misteria",
      "każdy dotrze do krainy odpowiadającej otrzymanym misteriom"
    )
    .replaceAll("w prawdzie tęskni za Bogiem", "szczerze tęskni za Bogiem")
    .replaceAll("prawdziwie tęskni za Bogiem", "szczerze tęskni za Bogiem")
    .replaceAll("przebaczcie mu, przepuśćcie go i dajcie mu", "przebaczcie mu, dopuśćcie go dalej i dajcie mu")
    .replaceAll("przebaczcie mu, przepuśćcie go dalej i dajcie mu", "przebaczcie mu, dopuśćcie go dalej i dajcie mu")
    .replaceAll("przepuśćcie także tego człowieka", "dopuśćcie także tego człowieka dalej")
    .replaceAll("Czy odpuszczają w typie |303. chrztów", "Czy odpuszczają na sposób |303. chrztów")
    .replaceAll("Czy odpuszczają w typie chrztów", "Czy odpuszczają na sposób chrztów")
    .replaceAll(
      "owe misteria są współczujące i odpuszczające po wszystkie czasy",
      "owe misteria są pełne współczucia i odpuszczają grzechy po wszystkie czasy"
    )
    .replaceAll(
      "Dlaczego więc czyni swoje ciało bezpożytecznym?",
      "Dlaczego więc na próżno trudzi swoje ciało?"
    )
    .replaceAll(
      "a jeśli jest zdatna, wtedy pozwoliłeś jej odziedziczyć Królestwo Światłości",
      "a jeśli okaże się godna, pozwól jej odziedziczyć Królestwo Światłości"
    )
    .replaceAll("lecz jeśli nie jest zdatna", "lecz jeśli okaże się niegodna")
    .replaceAll(
      "Czy zrozumieliście wszystkie te słowa i typ |313. tej kobiety?",
      "Czy zrozumieliście wszystkie te słowa i znaczenie |313. historii tej kobiety?"
    )
    .replaceAll(
      "zrozumiałam misteria rzeczy, które przypadły w udziale tej kobiecie",
      "zrozumiałam znaczenie tego, co spotkało tę kobietę"
    )
    .replaceAll(
      "Co do rzeczy więc, które jej przypadły, mówiłeś nam przedtem w podobieństwie",
      "To, co ją spotkało, zapowiedziałeś nam wcześniej w przypowieści"
    )
    .replaceAll(
      "pytasz pięknie swoim doskonałym pytaniem",
      "zadajesz piękne i doskonałe pytanie"
    )
    .replaceAll("objawię ci je w całej jawności", "objawię ci je jasno")
    .replaceAll("jaśniejąc bardzo nadzwyczajnie", "jaśniejąc niezwykle jasno")
    .replaceAll("jaśniał bardzo nadzwyczajnie", "jaśniał niezwykle jasno")
    .replaceAll("wielką niezmierzoną odległością", "niezmierzoną odległością")
    .replaceAll("a jeśli wyda owoc w następnym roku, pozwoliłeś mu trwać", "a jeśli wyda owoc w następnym roku, pozwól mu trwać")
    .replace(/(^|[\s([{„“"])['](?=\S)/g, "$1„")
    .replace(/(\S)['](?=$|[\s.,;:!?)}\]„“”"])/g, "$1”")
    .replace(/^'$/gm, "”")
    .replace(/ - /g, " — ");
}

return Object.fromEntries(
  Object.entries(polishTranslations).map(([page, text]) => [page, normalizePolishTypography(text)])
);
